SELECT users.user_id, users.user_name, COS(users.rating) AS user_cosine_rating
FROM users
INNER JOIN affiliate_programs ON users.platform_id = affiliate_programs.platform_id;

SELECT AVG(users.rating) AS AverageRating
  FROM users
  WHERE users.user_id IN (
      SELECT freelancer_id 
      FROM bids
  ) AND users.user_id IN (
      SELECT referred_user_id
      FROM referrals
  );

SELECT email 
FROM users 
WHERE role = 'freelancer' AND platform_id = (SELECT platform_id FROM platforms WHERE name = 'Upwork');
